module top_module (
    input l,
    input q,
    output reg invalid_g
);
    always @(*) begin
        case ({l, q})
            2'b00: invalid_g = 1'b1;
            2'b01: invalid_g = 1'b0;
            2'b11: invalid_g = 1'b1;
            2'b10: invalid_g = 1'b1;
        endcase
    end
endmodule
